//go:build integration

package testchain

// stakingBytecodeHex is the creation bytecode for the minimal test Staking fixture
// (see staking.go for the Solidity source). It exposes stake(uint256) (nonpayable,
// state-changing), earned(address)(uint256) (view), withdraw(uint256), getReward(),
// and a Staked(address indexed user, uint256 amount) event. No constructor args — it
// deploys from raw creation bytecode like erc20bytecode.go. Compiled offline with
// solc 0.8.26 (optimizer on, 200 runs) from the standalone, no-import source in
// staking.go and checked in so the integration test needs no solc at run time.
//
// Pinned selectors (re-derived from the signatures; the integration test asserts on
// them via Daxie's own decode/classify path, not these literals):
//
//	stake(uint256)    = 0xa694fc3a   earned(address)   = 0x008cc262
//	withdraw(uint256) = 0x2e1a7d4d   getReward()       = 0x3d18b912
//	Staked(address,uint256) topic0   = 0x9e71bc8eea02a63969f509818f2dafb9254532904319f9dbda79b67bd34a5f3d
const stakingBytecodeHex = ""
